function Skillspage() {
  const professionalRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("reveal");
          }
        });
      },
      { threshold: 0.3 },
    );

    observer.observe(professionalRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div>
      <div id="skill" className="thirdpage">
        <div className="skill-eyebrow">
          <span className="prompt-glyph">&gt;</span> ~/stack --list --verbose
        </div>
        <h1 ref={professionalRef}>
          Professional <span>Skillset</span>
        </h1>

        <div className="skills-container">
          {SKILLS.map((s) => (
            <div className="skills-box" key={s.name}>
              <div className="skill-header">
                <div className="language-emoji">
                  {s.icon ? (
                    s.icon
                  ) : (
                    <img
                      src={s.img || s.src}
                      alt={s.name}
                      width="26"
                      height="26"
                    />
                  )}
                </div>
                <div className="skill-meta">
                  <div className="skill-name">{s.name}</div>
                  <div className="skill-percent">
                    {s.percent}
                    <span>%</span>
                  </div>
                </div>
              </div>
              <div className="percentage-line">
                <div
                  className="skill-line"
                  style={{ width: `${s.percent}%` }}
                ></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Skillspage;